import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface HourlyIntake {
  hour: string;
  milliliters: number;
}

interface HydrationData {
  dailyGoal: {
    target: number;
    current: number;
    percentage: number;
  };
  hourlyIntake: HourlyIntake[];
}

export default function Widget() {
  const hydrationData = response.data as HydrationData;
  const { dailyGoal, hourlyIntake } = hydrationData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#42A5F5' }}>
              Daily Hydration
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              {dailyGoal.current} ml
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              of {dailyGoal.target} ml goal
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#42A5F5' }}>
                {dailyGoal.percentage}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={dailyGoal.percentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#E3F2FD',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#42A5F5',
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              series={[
                {
                  data: hourlyIntake.map(h => h.milliliters),
                  color: '#FFCA28',
                },
              ]}
              xAxis={[
                {
                  data: hourlyIntake.map(h => h.hour),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
